var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"으윽, 머리 가죽이 벗겨지는 줄 알았어……","JPN":"ううっ、頭皮がはがれるかと思ったよ……","ENG":"Ngh... I thought my scalp was gonna tear off...","TWN":"呃呃，頭皮都要被扯下來了……"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L3_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"학부장님 뒤만 정신없이 따라오긴 했는데…… 여긴 대체 어디일까요?","JPN":"学部長様の後ろを無我夢中に追ってはきましたけど……ここはいったいどこなのでしょう？","ENG":"Where are we? We just followed wherever the dean was going, and–","TWN":"雖然糊裡糊塗地跟著學院院長過來了……這裡究竟是哪裡？"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"방공호 같군. 대정화 전쟁 시절에 지었다가 방치된 모양이야.","JPN":"防空壕のようだな。大浄化戦争の頃に建設されてから、放置されていたようだ。","ENG":"It looks like a panic room. It was built during the Grand Purification War but was abandoned.","TWN":"好像是防空洞。似乎是淨化之戰時期建的，現在閒置了。"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_B","text":{"KOREA":"됐습니다. 여기라면 기관의 전략 위성도 한동안 추격에 애를 먹을 겁니다.","JPN":"教授、ここなら機関の戦略衛星もしばらく追撃に苦労するはずです。","ENG":"This should do. We should be able to hide from the Institution's satellites in here.","TWN":"可以了。這裡的話，機關的戰略衛星搜尋起來也得花一段時間。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"MERCENARY_NPC_ESPR2_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"그렇군. 전용기는 준비되었나?","JPN":"そうか。専用機の準備はできているか？","ENG":"Good. And what about the plane?","TWN":"是啊。專機準備好了嗎？"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_B","text":{"KOREA":"죄송합니다, 교수님. 비행장에서도 소요가 발생했다고 연락 받았습니다.","JPN":"申し訳ございません、教授。飛行場でも騒動が発生したとの連絡がありました。","ENG":"My apologies, Professor. I was informed that there was a problem at the airport as well.","TWN":"對不起，教授。剛剛接到通知，說是機場也發生了騷動。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"MERCENARY_NPC_ESPR2_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"그래. 기관장이 손을 썼나 보군…….","JPN":"うむ。機関長が手を回したようだな……","ENG":"I see. I guess the chief of the Institution stepped in...","TWN":"嗯，看來是機關長出手了……"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"버넷 경의 손자만 보냈다는 건 이목을 분산시키려는 계획임을 알아차렸기 때문이겠지. 영리한 아가씨야.","JPN":"バーネット卿の孫だけを向かわせたということは、注意を分散させる計画だと気付いたからだろう。賢いお嬢さんだ。","ENG":"By the looks of only sending out Sir Burnett's grandson, she probably figured out that this was all a distraction. Smart girl.","TWN":"只派出了伯內特卿的孫子，應該是看破我們的計畫，想分散他們的注意力吧。真是個聰明的小姐。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"추가로 배편을 수배해 주게. 브로커가 얼마를 부르든 상관없어.","JPN":"追加で船便を手配してくれ。ブローカーがいくらを要求しようと構わない。","ENG":"Find us a boat. I'll pay whatever the broker asks for.","TWN":"另外再去找一搜船。不管偷渡掮客要多少錢，都無所謂。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_B","text":{"KOREA":"예. 바로 알아 보겠습니다.","JPN":"はい。すぐに調べてみます。","ENG":"Yes, sir. I'll look for one right away.","TWN":"是的，我馬上去找。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"MERCENARY_NPC_ESPR2_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"이런 일에 휘말리게 해서 미안합니다, 맥크레디 양.","JPN":"こんなことに巻き込んでしまってすみません、マクレディーさん。","ENG":"I'm sorry you got tangled in this mess, Ms. MacCready.","TWN":"對不起，讓你捲進這種事，麥克蕾蒂。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_B","text":{"KOREA":"감히 교수님의 따귀를 때려! 무슨 짓이냐!","JPN":"教授のお顔を！　何をするんだ！","ENG":"Huh?! How dare you slap the Professor?!","TWN":"你竟敢打教授耳光！你在幹什麼！"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"가만히 있게. 내 제자이기 이전에 부학회장님이실세.","JPN":"静かに。私の教え子である前に副学会長なのだ。","ENG":"Halt. She is the Vice President before being my student.","TWN":"住手，她雖然是我的學生，但更是副學會長。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"……따귀를 맞은 건 오랜만이군요. 맥크레디 양도 어머니처럼 손맛이 매운 편입니다.","JPN":"……頬を叩かれたのは久しぶりですね。マクレディーさんの平手打ちはお母さんに似ていて痛いです。","ENG":"…It's been a while since someone slapped me. Your slaps feel just like your mother's.","TWN":"……好久沒挨耳光了。麥克蕾蒂下手也很重呢，跟你的母親一樣。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"대체 뭐죠……?","JPN":"いったい何なのですか……？","ENG":"What is all this...?","TWN":"究竟是怎麼回事……？"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"왜 당신이 고고학부장이에요? 합중국을 뒤엎는다는 건 또 무슨 소리고요?","JPN":"どうしてあなたが考古学部長なのですか？　合衆国をひっくり返すというのは、どういうことですの？","ENG":"Why are you the Dean of Archeology? And what is that about overtaking the States?","TWN":"你為什麼是考古學院院長？推翻合眾國又是什麼意思？"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"순서가 잘못되었습니다. 고고학부장인 제가 교수로 부임한 것이죠.","JPN":"順番が間違っています。考古学部長である私が、教授として赴任したわけです。","ENG":"The order is wrong. As Dean of Archeology, I was hired as a professor.","TWN":"順序錯了。應該說是身為考古學院院長的我赴任當了教授。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};